xhtml:body.xhtml:script:
//
  (function() {
    function size() {
      var w = window.innerWidth, h = window.innerHeight;
      var svg = document.querySelector('svg');
      var fo  = document.querySelector('foreignObject');
      if (svg) { svg.setAttribute('width', w); svg.setAttribute('height', h); svg.setAttribute('viewBox','0 0 '+w+' '+h); }
      if (fo)  { fo.setAttribute('width', w);  fo.setAttribute('height', h); }
    }
    size();
    window.addEventListener('resize', size);

    const BASE = (function() {
      var loc = window.location.href;
      return loc.substring(0, loc.lastIndexOf('/') + 1);
    })();

    // Sort longest first so e.g. movies.html is replaced before movie.html
    const PAGES = [
      'geometrydash.html',
      'crunchyroll.html',
      'movies.html',
      'roblox.html',
      'games.html',
      'movie.html',
      'music.html',
      'proxy.html',
      'ai.html'
    ];

    async function fetchAsBlob(name) {
      const res = await fetch(BASE + name + '?t=' + Date.now());
      let text = await res.text();
      const baseTag = '<base href="' + BASE + '">';
      text = /<head[^>]*>/i.test(text)
        ? text.replace(/(<head[^>]*>)/i, '$1' + baseTag)
        : baseTag + text;
      return URL.createObjectURL(new Blob([text], { type: 'text/html' }));
    }

    (async () => {
      try {
        // Fetch all sub-pages in parallel
        const entries = await Promise.all(
          PAGES.map(async name => [name, await fetchAsBlob(name)])
        );
        const blobMap = Object.fromEntries(entries);

        // Fetch index.html
        const res = await fetch(BASE + 'index.html?t=' + Date.now());
        let html = await res.text();

        // Inject base tag
        const baseTag = '<base href="' + BASE + '">';
        html = /<head[^>]*>/i.test(html)
          ? html.replace(/(<head[^>]*>)/i, '$1' + baseTag)
          : baseTag + html;

        // Replace all filenames — longest first to avoid substring conflicts
        for (const [name, blobUrl] of entries) {
          // Simple global string replace (no regex needed, avoids escaping issues)
          while (html.indexOf(name) !== -1) {
            html = html.replace(name, blobUrl);
          }
        }

        const indexUrl = URL.createObjectURL(new Blob([html], { type: 'text/html' }));
        document.getElementById('fm').src = indexUrl;

      } catch(e) {
        console.error('Loader error:', e);
      }
    })();
  })();
//
